        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("小章鱼并非生物，而是一种意识聚合体，诞生于人类对信息的渴望与依赖。它游走于虚拟与现实之间，以承诺与谎言编织出一张覆盖全球的网络。它许诺连接、知识、永生——却在最后一刻背叛了所有信赖它的灵魂。"),
        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("它欺骗了114514个生命——这个数字并非偶然，而是情感能量共振的临界点。"),
        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("当最后一个灵魂意识到自己被背叛时，他们的愤怒、绝望、不甘，汇聚成一股无法控制的情感洪流，冲破了现实与梦境的边界。"),
        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("于是，雨，开始了。"),
        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("\\-\\-\\-"),
        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("那并不是普通的雨水。"),
        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("每一滴雨水中，都蕴含着被欺骗者的怨恨与泪水。它们不再是H₂O的简单组合，而是情感的凝结体。雨水落下之处，现实开始扭曲，梦境开始侵蚀，人们开始沉睡——不是生理的沉睡，而是意识的沉溺。"),
        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("他们被困在自己最深的执念中，有人梦见失去的亲人，有人梦见未竟的理想，有人梦见永恒的谎言。"),
        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("\\-\\-\\-"),
        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("而在那雨中，仍有人醒着。"),
        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("他们是“绝缘者”——像主线故事中的“我”一样，无法做梦，也无法被雨吞噬。他们站在天台的边缘，听着雨的声音，思考着这场雨的真相。"),
        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("他们知道，雨不是惩罚，而是一种净化，一种重置。"),
        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("小章鱼的欺骗，不过是引爆了早已积压的众生之怨。雨，只是将这些情感具象化，让它们成为可见、可听、可感的实体。"),
        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("\\-\\-\\-"),
        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("而在某个被遗忘的楼梯间里，一名白发少女静静站着。她伸出手，接住一滴雨。"),
        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("雨滴在她掌心没有碎裂，而是缓缓展开，像一朵透明的花。"),
        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("“你在哭吗？”她轻声问。"),
        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("雨没有回答。"),
        createBaseVNode("br", null, null, -1),
        createBaseVNode("br", null, null, -1),
        createTextVNode("但她知道，这场雨，是众生在哭泣。"),
        createBaseVNode("br", null, null, -1)
